import React from 'react';

function UploadPreview(props) {

    const files = props.files.map(file => (
        <div><img src={URL.createObjectURL(file)}/></div>
    ));

    // const imagePrevie = ()

    return (
        <div>   
            {files}
        </div>
    )
}

export default UploadPreview;
